# Check if script exists
if not os.path.isfile(script_path):
    raise ValueError(f"Script '{script_path}' does not exist.")

# Start the subprocess
process = subprocess.Popen(
    [script_path],
    stdout=subprocess.PIPE,
    stderr=subprocess.PIPE,
    shell=True
)

# Get the process object for monitoring
try:
    proc = psutil.Process(process.pid)
except psutil.NoSuchProcess:
    raise RuntimeError(f"Process {process.pid} not found.")

cpu_usage = 0.0
memory_usage = 0.0
start_time = time.time()

try:
    while True:
        # Check if process is still running
        if not proc.is_running():
            break

        # Check for zombie process
        if proc.status() == psutil.STATUS_ZOMBIE:
            break

        # Get CPU and memory usage
        try:
            cpu_percent = proc.cpu_percent(interval=0.1)
            memory_info = proc.memory_info()
            memory_usage += memory_info.rss
            cpu_usage += cpu_percent
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            break

        # Check timeout
        if time.time() - start_time > timeout:
            process.terminate()
            try:
                process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                process.kill()
            break

        time.sleep(0.1)

except Exception:
    pass

# Final check for process completion
if process.poll() is None:
    process.terminate()
    try:
        process.wait(timeout=5)
    except subprocess.TimeoutExpired:
        process.kill()

return {
    'CPU Usage': cpu_usage,
    'Memory Usage': int(memory_usage)
}

