if interval <= 0 or duration <= 0:
    raise ValueError("Both interval and duration must be greater than zero.")

log_data = []
start_time = time.time()
end_time = start_time + duration

# Determine the appropriate command based on the platform
if platform.system() == "Windows":
    cmd = ["wmic", "cpu", "get", "loadpercentage"]
else:
    cmd = ["top", "-bn1"]

try:
    while time.time() < end_time:
        # Capture CPU usage
        if platform.system() == "Windows":
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=5)
            if result.returncode == 0:
                output = result.stdout.strip()
                # Extract the numeric value from the output
                cpu_usage = None
                for line in output.splitlines():
                    line = line.strip()
                    if line.isdigit():
                        cpu_usage = int(line)
                        break
                if cpu_usage is None:
                    cpu_usage = 0
            else:
                cpu_usage = 0
        else:
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=5)
            if result.returncode == 0:
                output = result.stdout
                # Parse the CPU usage from the top command output
                cpu_usage = None
                for line in output.splitlines():
                    if "Cpu(s)" in line:
                        # Example: "Cpu(s):  0.0%us,  0.0%sy,  0.0%ni, 99.9%id,  0.0%wa,  0.0%hi,  0.0%si,  0.0%st"
                        parts = line.split(',')
                        if len(parts) > 3:
                            id_part = parts[3].strip()
                            # Extract percentage value
                            try:
                                cpu_usage = 100 - float(id_part[:-1])  # id% is idle, so usage = 100 - idle
                            except ValueError:
                                cpu_usage = 0
                        break
                if cpu_usage is None:
                    cpu_usage = 0
            else:
                cpu_usage = 0

        # Record the timestamp and CPU usage
        record = {
            "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
            "cpu_usage_percent": cpu_usage
        }
        log_data.append(record)

        # Wait for the next interval
        time.sleep(max(0, interval - (time.time() - start_time) % interval))

    # Write the log data to the file
    with open(LOGFILE_PATH, "w", encoding="utf-8") as log_file:
        json.dump(log_data, log_file, indent=2)

    return LOGFILE_PATH

except (subprocess.TimeoutExpired, subprocess.CalledProcessError, IOError) as e:
    print(f"Error during CPU monitoring: {e}")
    return None

