def is_divisible_by_11(n):
    # Convert to string to easily access digits
    s = str(abs(n))  # Use abs to handle negative numbers
    # Calculate alternating sum of digits
    alt_sum = 0
    for i, digit in enumerate(s):
        if i % 2 == 0:
            alt_sum += int(digit)
        else:
            alt_sum -= int(digit)
    # A number is divisible by 11 if the alternating sum is divisible by 11
    return alt_sum % 11 == 0

